<?php

namespace App\Controllers\Admin;

use App\Controllers\AdminBaseController;
use App\Models\Admin\SiswaModel;
use App\Models\Admin\RombelModel;
use App\Models\Admin\ValidasiNilaiModel;
use Mpdf\Mpdf;

class CetakRaporController extends AdminBaseController
{
    protected $siswaModel;
    protected $rombelModel;
    protected $validasiModel;
    protected $db;

    public function __construct()
    {
        $this->siswaModel = new SiswaModel();
        $this->rombelModel = new RombelModel();
        $this->validasiModel = new ValidasiNilaiModel();
        $this->db = \Config\Database::connect();
    }

    public function index()
    {
        $this->data['title'] = 'Cetak Rapor Siswa';
        $this->data['color'] = $this->getColor();

        // 1. DINAMISASI: Ambil Tahun Ajaran Aktif dari tabel tahun_ajaran
        // Mengambil baris pertama yang statusnya 'Aktif'
        $ta_aktif = $this->db->table('tahun_ajaran')->where('status', 'Aktif')->get()->getRowArray();
        
        // Simpan nilai tahun dan semester aktif ke dalam data array untuk View
        // Jika tidak ada yang aktif, berikan nilai default agar sistem tidak error
        $this->data['tahun_ajaran_aktif'] = $ta_aktif ? $ta_aktif['tahun'] : '2024/2025';
        $this->data['semester_aktif']     = $ta_aktif ? $ta_aktif['semester'] : 'Genap';

        // 2. AMBIL DATA ROMBEL: Tampilkan dengan format "Tingkat - Nama Rombel"
        $this->data['list_rombel'] = $this->rombelModel
            ->select('id, tingkat, nama_rombel')
            ->orderBy('tingkat', 'ASC') // Urutkan berdasarkan angkatan dulu
            ->orderBy('nama_rombel', 'ASC')
            ->findAll();

        return view('admin/cetak-rapor', $this->data);
    }

    public function getSiswaByRombel()
    {
        $rombel_id = $this->request->getGet('rombel_id');
        if(!$rombel_id) return $this->response->setJSON(['status' => 'error']);

        $siswa = $this->siswaModel
            ->select('id, nama_lengkap, nis')
            ->where('rombel_id', $rombel_id)
            ->where('status_siswa', 'Aktif')
            ->orderBy('nama_lengkap', 'ASC')
            ->findAll();

        $validasi = $this->validasiModel->where('rombel_id', $rombel_id)->first();

        $status_rombel = [
            'is_locked' => $validasi && $validasi['is_locked'] == 1,
            'locked_at' => $validasi ? date('d M Y, H:i', strtotime($validasi['locked_at'])) : '-',
            'validator' => 'Waka Kurikulum'
        ];

        return $this->response->setJSON([
            'status' => 'success',
            'data_siswa' => $siswa,
            'info_rombel' => $status_rombel
        ]);
    }

    public function saveCatatanRapor()
    {
        $db = \Config\Database::connect();
        $siswaId = $this->request->getPost('siswa_id');
        
        // 1. DINAMISASI SAAT MENYIMPAN CATATAN & ABSENSI
        // Pastikan data yang disimpan merujuk pada tahun ajaran yang sedang aktif
        $ta_aktif = $this->db->table('tahun_ajaran')->where('status', 'Aktif')->get()->getRowArray();
        $tahun    = $ta_aktif ? $ta_aktif['tahun'] : '2024/2025';
        $semester = $ta_aktif ? $ta_aktif['semester'] : 'Genap';

        // Menyiapkan data catatan rapor
        $dataCatatan = [
            'siswa_id'           => $siswaId,
            'tahun_ajaran'       => $tahun, // Menggunakan tahun dinamis
            'semester'           => $semester, // Menggunakan semester dinamis
            'kata_pengantar'     => $this->request->getPost('kata_pengantar'),
            'catatan_wali_kelas' => $this->request->getPost('catatan_wali'),
            'status_kenaikan'    => $this->request->getPost('status_kenaikan')
        ];

        $builderCatatan = $db->table('catatan_rapor');
        // Cek apakah catatan untuk siswa di semester ini sudah ada
        $existCatatan = $builderCatatan->where('siswa_id', $siswaId)
                                       ->where('tahun_ajaran', $tahun)
                                       ->where('semester', $semester)
                                       ->get()->getRow();

        if ($existCatatan) {
            $builderCatatan->where('id', $existCatatan->id)->update($dataCatatan);
        } else {
            $builderCatatan->insert($dataCatatan);
        }

        // Menyiapkan data rekap absensi
        $dataAbsen = [
            'siswa_id'     => $siswaId,
            'tahun_ajaran' => $tahun, // Menggunakan tahun dinamis
            'semester'     => $semester, // Menggunakan semester dinamis
            'sakit'        => $this->request->getPost('sakit'),
            'izin'         => $this->request->getPost('izin'),
            'alpha'        => $this->request->getPost('alpha')
        ];

        $builderAbsen = $db->table('rekap_absensi');
        // Cek apakah absensi untuk siswa di semester ini sudah ada
        $existAbsen = $builderAbsen->where('siswa_id', $siswaId)
                                   ->where('tahun_ajaran', $tahun)
                                   ->where('semester', $semester)
                                   ->get()->getRow();

        if ($existAbsen) {
            $builderAbsen->where('id', $existAbsen->id)->update($dataAbsen);
        } else {
            $builderAbsen->insert($dataAbsen);
        }

        return $this->response->setJSON(['status' => 'success']);
    }

    public function printPDF($siswa_id, $action = 'preview')
    {
        $db = \Config\Database::connect();

        // 1. Ambil Parameter dari URL (GET Request yang dikirim oleh JS)
        $jenisRapor = $this->request->getGet('jenis_rapor') ?? 'lengkap';
        $optCover   = $this->request->getGet('cover') === 'true';
        $optTtd     = $this->request->getGet('ttd') === 'true';
        $optQr      = $this->request->getGet('qr') === 'true';

        // 2. Tahun Ajaran Aktif
        $ta_aktif = $db->table('tahun_ajaran')->where('status', 'Aktif')->get()->getRowArray();
        $tahun_ajaran = $ta_aktif ? $ta_aktif['tahun'] : '2025/2026';
        $semester     = $ta_aktif ? $ta_aktif['semester'] : 'Genap';

        // 3. Tarik Data Siswa & Sekolah (Sama seperti sebelumnya)
        $siswa = $this->siswaModel
            ->select('siswa.*, rombel.nama_rombel, rombel.tingkat, guru_tendik.nama_lengkap as wali_kelas, guru_tendik.nuptk as wali_nuptk')
            ->join('rombel', 'rombel.id = siswa.rombel_id')
            ->join('guru_tendik', 'guru_tendik.id = rombel.wali_kelas_id', 'left')
            ->find($siswa_id);

        if (!$siswa) return "Data siswa tidak ditemukan.";

        $sekolah = $db->table('sekolah')->get()->getRowArray();
        $kepsek = $db->table('guru_tendik')->like('jabatan', 'Kepala Sekolah', 'both')->get()->getRowArray();

        // 4. Tarik Nilai & Catatan
        $nilai = $db->table('nilai_akademik n')
            ->select('n.mapel_id, m.nama_mapel, AVG(n.nilai_angka) as nilai_akhir, MIN(m.kkm) as kkm')
            ->join('mata_pelajaran m', 'm.id = n.mapel_id', 'left')
            ->where('n.siswa_id', $siswa_id)
            ->where('n.tahun_ajaran', $tahun_ajaran)
            ->where('n.semester', $semester)
            ->groupBy('n.mapel_id, m.nama_mapel')
            ->get()->getResultArray();

        // --- (Proses Kalkulasi Predikat seperti sebelumnya) ---
        $aturanPredikat = $db->table('setting_aturan_nilai')->get()->getResultArray();
        foreach ($nilai as &$n) {
            $n['nilai_akhir'] = round($n['nilai_akhir']);
            $n['kkm'] = $n['kkm'] ?? 75; 
            $n['predikat'] = 'D'; 
            $n['deskripsi'] = 'Perlu bimbingan.'; 
            foreach ($aturanPredikat as $aturan) {
                if ($n['nilai_akhir'] >= $aturan['nilai_min'] && $n['nilai_akhir'] <= $aturan['nilai_max']) {
                    $n['predikat'] = $aturan['predikat'];
                    $n['deskripsi'] = $aturan['deskripsi_kompetensi'];
                    break;
                }
            }
        }

        $catatan = $db->table('catatan_rapor')
            ->where('siswa_id', $siswa_id)
            ->where('tahun_ajaran', $tahun_ajaran)
            ->where('semester', $semester)
            ->get()->getRowArray();

        $absenData = $db->table('rekap_absensi')
            ->where('siswa_id', $siswa_id)
            ->where('tahun_ajaran', $tahun_ajaran)
            ->where('semester', $semester)
            ->get()->getRowArray();
        $absen = $absenData ? $absenData : ['sakit' => 0, 'izin' => 0, 'alpha' => 0];

        $ekskul = $db->table('nilai_ekskul')->where('siswa_id', $siswa_id)->get()->getResultArray();
        
        $tahfidz = [];
        if ($db->tableExists('nilai_tahfidz')) {
            $tahfidz = $db->table('nilai_tahfidz')->where('siswa_id', $siswa_id)->get()->getRowArray();
        }

        // 5. Siapkan Paket Data
        $data = [
            'siswa'           => $siswa,
            'nilai'           => $nilai,
            'catatan'         => $catatan,
            'tahfidz'         => $tahfidz,
            'absen'           => $absen,   
            'ekskul'          => $ekskul, 
            'sekolah'         => $sekolah,
            'kepsek'          => $kepsek,
            'tahun_ajaran'    => $tahun_ajaran,
            'semester'        => $semester,
            'tanggal_rapor'   => date('d F Y'),
            
            // Pengaturan Opsi
            'opt_cover'       => $optCover,
            'opt_ttd'         => $optTtd,
            'opt_qr'          => $optQr
        ];

        // 6. LOGIKA PEMILIHAN TEMPLATE BERDASARKAN JENIS RAPOR
        $html = '';
        
        // Panggil Cover jika dicentang (File ini akan dicetak paling awal)
        if ($optCover) {
            $html .= view('admin/print/partials/rapor_cover', $data);
        }

        // Pilih body rapor berdasarkan jenis
        if ($jenisRapor === 'akademik') {
            $html .= view('admin/print/rapor_akademik', $data);
        } elseif ($jenisRapor === 'karakter') {
            $html .= view('admin/print/rapor_karakter', $data);
        } else {
            // Default (lengkap)
            $html .= view('admin/print/rapor_lengkap', $data);
        }

        // 7. Inisialisasi mPDF
        $mpdf = new \Mpdf\Mpdf([
            'mode' => 'utf-8', 
            'format' => 'A4',
            'margin_top' => 10, 
            'margin_bottom' => 10, 
            'margin_left' => 15, 
            'margin_right' => 15
        ]);

        // 2. LOGO TENGAH (WATERMARK)
        // PERHATIAN: Ganti 'PASTE_KODE_DISINI' dengan kode Base64 Logo Emas Anda yang panjang.
        $logoBase64 = 'data:image/png;base64,'; 

        $mpdf->SetWatermarkImage(
            $logoBase64, 
            0.2,           // Opacity
            [100, 100],     // Ukuran
            'F'             // Posisi
        );
        $mpdf->showWatermarkImage = true;

        $mpdf->SetFooter('Rapor Siswa - SMPIT Ad Durrah||Halaman {PAGENO}');
        $mpdf->WriteHTML($html);

       $filename = 'Rapor_' . $siswa['nis'] . '_' . ucfirst($jenisRapor) . '.pdf';
        
        $dest = ($action == 'download') ? 'D' : 'I';
        return $this->response->setHeader('Content-Type', 'application/pdf')
            ->setBody($mpdf->Output($filename, $dest));
    }
}